module top_module(
    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;
  wire _tap_X = X ^ {1{1'b0}};


    // Module supplies
    supply1 KAPWR;
    supply0 VGND ;
    supply1 VPB  ;
    supply0 VNB  ;

    // Local signals
    wire sleepn;

    //  Name  Output  Other arguments
    not not0 (sleepn, SLEEP          );
    and and0 (X     , A, sleepn      );

endmodule
